// src/App.js

import React, { useState } from "react";
import FileUploader from "./components/FileUploader";
import PreviewPanel from "./components/PreviewPanel";
import { previewAssignment, downloadAssignment } from "./services/api";
import "./App.css";

const LOADING_STAGES = [
  "Reading your assignment file...",
  "Sending to Hugging Face AI model...",
  "AI is writing your assignment (this may take 1-2 minutes)...",
  "Formatting and structuring the content...",
];

export default function App() {
  const [file, setFile] = useState(null);
  const [studentName, setStudentName] = useState("");
  const [enrollment, setEnrollment] = useState("");
  const [subjectName, setSubjectName] = useState("");
  const [outputFormat, setOutputFormat] = useState("auto"); // "auto" | "pdf" | "docx"
  const [loading, setLoading] = useState(false);
  const [loadingStage, setLoadingStage] = useState(0);
  const [preview, setPreview] = useState(null);
  const [error, setError] = useState("");
  const [isDownloading, setIsDownloading] = useState(false);
  const [successMsg, setSuccessMsg] = useState("");

  const startLoadingCycle = () => {
    setLoadingStage(0);
    let stage = 0;
    const interval = setInterval(() => {
      stage = Math.min(stage + 1, LOADING_STAGES.length - 1);
      setLoadingStage(stage);
    }, 15000);
    return interval;
  };

  // Resolve actual format: "auto" means match input file
  const getActualFormat = () => {
    if (outputFormat !== "auto") return outputFormat;
    if (!file) return "docx";
    return file.name.split(".").pop().toLowerCase() === "pdf" ? "pdf" : "docx";
  };

  const handleGenerate = async (e) => {
    e.preventDefault();
    setError("");
    setPreview(null);
    setSuccessMsg("");

    if (!file) return setError("Please upload your assignment file.");
    if (!studentName.trim()) return setError("Please enter your full name.");
    if (!enrollment.trim()) return setError("Please enter your enrollment number.");

    setLoading(true);
    const interval = startLoadingCycle();

    try {
      const data = await previewAssignment(file, studentName.trim(), enrollment.trim(), subjectName.trim());
      setPreview(data);
    } catch (err) {
      setError(err.response?.data?.error || err.message || "Something went wrong.");
    } finally {
      clearInterval(interval);
      setLoading(false);
    }
  };

  const handleDownload = async () => {
    setIsDownloading(true);
    setSuccessMsg("");
    const fmt = getActualFormat();
    try {
      const filename = await downloadAssignment(file, studentName.trim(), enrollment.trim(), fmt, subjectName.trim());
      setSuccessMsg(`✅ "${filename}" downloaded successfully!`);
    } catch (err) {
      setError(err.response?.data?.error || err.message || "Download failed.");
    } finally {
      setIsDownloading(false);
    }
  };

  const handleReset = () => {
    setFile(null);
    setStudentName("");
    setEnrollment("");
    setSubjectName("");
    setOutputFormat("auto");
    setPreview(null);
    setError("");
    setSuccessMsg("");
  };

  return (
    <div className="app">
      {/* ── HEADER ── */}
      <header className="header">
        <div className="header-content">
          <div className="logo">
            <span className="logo-icon">🎓</span>
            <div>
              <h1>AssignmentAI</h1>
              <p>Powered by Hugging Face · Mixtral 8x7B</p>
            </div>
          </div>
        </div>
      </header>

      <main className="main">
        {/* ── LEFT: FORM ── */}
        <section className="form-section">
          <div className="card">
            <h2 className="card-title"><span>📋</span> Generate Your Assignment</h2>
            <p className="card-subtitle">
              Upload your assignment questions (.docx or .pdf) and get a complete AI-written solution.
            </p>

            <form onSubmit={handleGenerate} className="form">
              {/* Student Name */}
              <div className="field">
                <label htmlFor="studentName">Full Name *</label>
                <input
                  id="studentName"
                  type="text"
                  placeholder="e.g. Rahul Sharma"
                  value={studentName}
                  onChange={(e) => setStudentName(e.target.value)}
                  disabled={loading}
                />
              </div>

              {/* Enrollment */}
              <div className="field">
                <label htmlFor="enrollment">Enrollment / Roll Number *</label>
                <input
                  id="enrollment"
                  type="text"
                  placeholder="e.g. 21BCE1234"
                  value={enrollment}
                  onChange={(e) => setEnrollment(e.target.value)}
                  disabled={loading}
                />
              </div>

              {/* Subject Name */}
              <div className="field">
                <label htmlFor="subjectName">Subject Name (optional)</label>
                <input
                  id="subjectName"
                  type="text"
                  placeholder="e.g. Network and Cyber Security (CSE900TR1)"
                  value={subjectName}
                  onChange={(e) => setSubjectName(e.target.value)}
                  disabled={loading}
                />
              </div>

              {/* File Upload */}
              <div className="field">
                <label>Upload Assignment File * (.docx / .doc / .pdf)</label>
                <FileUploader onFileSelect={setFile} selectedFile={file} />
              </div>

              {/* Output Format Selector */}
              <div className="field">
                <label>Output Format</label>
                <div className="format-selector">
                  {[
                    { value: "auto", label: "🔄 Auto (same as input)" },
                    { value: "pdf",  label: "📕 PDF" },
                    { value: "docx", label: "📄 Word (.docx)" },
                  ].map((opt) => (
                    <button
                      key={opt.value}
                      type="button"
                      className={`format-btn ${outputFormat === opt.value ? "format-btn-active" : ""}`}
                      onClick={() => setOutputFormat(opt.value)}
                      disabled={loading}
                    >
                      {opt.label}
                    </button>
                  ))}
                </div>
                {file && (
                  <p className="format-hint">
                    Will generate: <strong>.{getActualFormat().toUpperCase()}</strong>
                  </p>
                )}
              </div>

              {/* Error */}
              {error && <div className="error-box">❌ {error}</div>}

              {/* Success */}
              {successMsg && <div className="success-box">{successMsg}</div>}

              {/* Submit */}
              <button
                type="submit"
                className="submit-btn"
                disabled={loading || !file || !studentName || !enrollment}
              >
                {loading ? "⏳ Generating..." : "🚀 Generate Assignment"}
              </button>

              {preview && (
                <button type="button" className="reset-btn" onClick={handleReset}>
                  🔄 Start New
                </button>
              )}
            </form>
          </div>

          {/* ── HOW IT WORKS ── */}
          <div className="how-it-works">
            <h3>How It Works</h3>
            <div className="steps">
              {[
                "Enter your name & enrollment number",
                "Upload your assignment .docx or .pdf with questions",
                "Choose output format: PDF or Word",
                "AI writes complete answers with your name & enrollment in header",
              ].map((text, i) => (
                <div className="step" key={i}>
                  <span className="step-num">{i + 1}</span>
                  <p>{text}</p>
                </div>
              ))}
            </div>
          </div>
        </section>

        {/* ── RIGHT: PREVIEW / LOADING ── */}
        <section className="preview-section">
          {loading ? (
            <div className="loading-card">
              <div className="spinner"></div>
              <h3>AI is writing your assignment</h3>
              <p className="loading-stage">{LOADING_STAGES[loadingStage]}</p>
              <p className="loading-note">
                Hugging Face models may take 1–3 minutes on first request (cold start). Please wait.
              </p>
              <div className="loading-bar">
                <div className="loading-bar-fill"></div>
              </div>
            </div>
          ) : preview ? (
            <PreviewPanel
              studentName={preview.studentName}
              enrollment={preview.enrollment}
              content={preview.generatedContent}
              wordCount={preview.wordCount}
              outputFormat={getActualFormat()}
              onDownload={handleDownload}
              isDownloading={isDownloading}
            />
          ) : (
            <div className="empty-state">
              <span className="empty-icon">📝</span>
              <h3>Your Assignment Preview</h3>
              <p>
                Fill in your details, upload your assignment file (.docx or .pdf), and click{" "}
                <strong>Generate Assignment</strong> to see a preview here.
              </p>
              <div className="format-badges">
                <span className="badge badge-docx">📄 DOCX Input/Output</span>
                <span className="badge badge-pdf">📕 PDF Input/Output</span>
              </div>
              <div className="model-badge">
                🤗 Model: mistralai/Mixtral-8x7B-Instruct-v0.1
              </div>
            </div>
          )}
        </section>
      </main>
    </div>
  );
}
